-- ============================================================
-- Migration 013: Seed all US SeeClickFix cities
-- ============================================================
-- Expands Fault Line coverage from 69 New England authorities to
-- 784 authorities nationwide by adding every US city that uses
-- SeeClickFix as its 311-equivalent intake system.
--
-- Data source: scraped seeclickfix.com/recent_place_stats (canonical
-- city directory) on 2026-04-21. 738 unique US cities confirmed;
-- 23 already existed in our DB (UPDATE to add SeeClickFix API as
-- priority 1); 715 new (INSERT).
--
-- Boundaries are NOT included in this migration — they're populated
-- post-hoc by invoking the enrich-authority-boundaries edge function
-- in batches of 200.
-- ============================================================

-- ------------------------------------------------------------
-- UPDATE 23 existing authorities: add SeeClickFix API as priority 1
-- ------------------------------------------------------------
UPDATE authorities SET submission_methods = 
  (jsonb_build_array('{   "method": "api",   "endpoint": "https://seeclickfix.com/api/v2/issues",   "priority": 1,   "protocol": "seeclickfix",   "notes": "SeeClickFix API (routes by lat/lng)" }'::jsonb) || submission_methods)
  WHERE state = 'CT' AND city = 'Bridgeport' AND NOT (submission_methods @> '[{"protocol": "seeclickfix"}]');

